package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair8211DifferenceFindingTest {

    private final ClonePair8211 subject = new ClonePair8211();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: exception.
     * Difference manifestation: the methods differ in thrown exceptions or normal completion.
     */
    @Test
    @BehavioralDifference(DifferenceType.EXCEPTION)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{throwingToStringObject()};
        InvocationOutcome method1Outcome = capture(values -> subject.method1(values[0]), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2(values[0]), inputs);

        assertCoreOutcome(
            method1Outcome,
            "EX",
            null,
            "java.lang.IllegalStateException",
            "java.lang.Object[][ThrowingToStringObject]",
            "java.lang.Object[][ThrowingToStringObject]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Boolean(false)",
            null,
            "java.lang.Object[][ThrowingToStringObject]",
            "java.lang.Object[][ThrowingToStringObject]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
